package com.friady.sailens.data.service

import android.content.Context
import com.friady.sailens.domain.model.trace.TraceSessionDescriptor
import com.friady.sailens.domain.service.TraceReplayService
import java.io.File

class FileTraceReplayService(
    private val context: Context,
) : TraceReplayService {
    override fun listSessions(): List<TraceSessionDescriptor> {
        return traceDirectory()
            .listFiles { file -> file.isFile && file.name.startsWith("trace_") && file.extension == "jsonl" }
            ?.sortedByDescending { it.lastModified() }
            ?.map { file ->
                TraceSessionDescriptor(
                    sessionId = file.nameWithoutExtension.removePrefix("trace_"),
                    fileName = file.name,
                    lastModifiedAt = file.lastModified(),
                )
            }
            ?: emptyList()
    }

    override fun readSessionLines(sessionId: String): List<String> {
        val file = File(traceDirectory(), "trace_$sessionId.jsonl")
        if (!file.exists() || !file.isFile) return emptyList()
        return file.readLines()
    }

    private fun traceDirectory(): File = File(context.filesDir, "traces")
}

package com.friady.sailens.domain.service

import com.friady.sailens.domain.model.trace.TraceSessionDescriptor

interface TraceReplayService {
    fun listSessions(): List<TraceSessionDescriptor>
    fun readSessionLines(sessionId: String): List<String>
}

package com.friady.sailens.domain.usecase.trace

import com.friady.sailens.domain.model.trace.TraceReplayReport

data class TraceReplayBudgetEvaluation(
    val isWithinBudget: Boolean,
    val warnings: List<String>,
)

class EvaluateTraceReplayBudgetUseCase {
    companion object {
        const val TARGET_P95_TOTAL_PIPELINE_MS = 85L
        const val MAX_DROPPED_FRAME_RATE = 0.10
    }

    operator fun invoke(report: TraceReplayReport): TraceReplayBudgetEvaluation {
        val warnings = buildList {
            if (report.p95TotalPipelineMs > TARGET_P95_TOTAL_PIPELINE_MS) {
                add(
                    "p95 total pipeline ${report.p95TotalPipelineMs}ms exceeds ${TARGET_P95_TOTAL_PIPELINE_MS}ms"
                )
            }

            val droppedFrameRate = if (report.totalFrames > 0) {
                report.droppedFrames.toDouble() / report.totalFrames
            } else {
                0.0
            }
            if (droppedFrameRate > MAX_DROPPED_FRAME_RATE) {
                add(
                    "dropped frame rate ${(droppedFrameRate * 100).toInt()}% exceeds ${(MAX_DROPPED_FRAME_RATE * 100).toInt()}%"
                )
            }
        }

        return TraceReplayBudgetEvaluation(
            isWithinBudget = warnings.isEmpty(),
            warnings = warnings,
        )
    }
}

package com.friady.sailens.domain.usecase.trace

import com.friady.sailens.domain.model.trace.TraceSessionDescriptor
import com.friady.sailens.domain.service.TraceReplayService

class ListTraceSessionsUseCase(
    private val traceReplayService: TraceReplayService,
) {
    operator fun invoke(): List<TraceSessionDescriptor> = traceReplayService.listSessions()
}

package com.friady.sailens.domain.usecase.trace

import com.friady.sailens.domain.model.trace.TraceReplayReport

class LoadLatestTraceReplayReportUseCase(
    private val listTraceSessionsUseCase: ListTraceSessionsUseCase,
    private val loadTraceReplayReportUseCase: LoadTraceReplayReportUseCase,
) {
    operator fun invoke(): TraceReplayReport? {
        val latestSession = listTraceSessionsUseCase().firstOrNull() ?: return null
        return loadTraceReplayReportUseCase(latestSession.sessionId)
    }
}

package com.friady.sailens.domain.usecase.trace

import com.friady.sailens.domain.model.trace.TraceReplayReport
import com.friady.sailens.domain.service.TraceReplayService

class LoadTraceReplayReportUseCase(
    private val traceReplayService: TraceReplayService,
    private val buildTraceReplayReportUseCase: BuildTraceReplayReportUseCase,
) {
    operator fun invoke(sessionId: String): TraceReplayReport? {
        val lines = traceReplayService.readSessionLines(sessionId)
        if (lines.isEmpty()) return null
        return buildTraceReplayReportUseCase(lines)
    }
}

package com.friady.sailens.domain.usecase.trace

import com.friady.sailens.domain.model.trace.TraceSessionDescriptor
import com.friady.sailens.domain.service.TraceReplayService

class FakeTraceReplayService(
    private val sessions: List<TraceSessionDescriptor> = emptyList(),
    private val linesBySessionId: Map<String, List<String>> = emptyMap(),
) : TraceReplayService {
    override fun listSessions(): List<TraceSessionDescriptor> = sessions

    override fun readSessionLines(sessionId: String): List<String> = linesBySessionId[sessionId].orEmpty()
}

package com.friady.sailens.domain.usecase.trace

import com.friady.sailens.domain.model.trace.TraceSessionDescriptor
import org.junit.Assert.assertEquals
import org.junit.Assert.assertNull
import org.junit.Assert.assertTrue
import org.junit.Test

class TraceReplayEntryPointsUseCaseTest {
    @Test
    fun `list trace sessions returns newest-first descriptors from replay service`() {
        val sessions = listOf(
            TraceSessionDescriptor(
                sessionId = "session-b",
                fileName = "trace_session-b.jsonl",
                lastModifiedAt = 20L,
            ),
            TraceSessionDescriptor(
                sessionId = "session-a",
                fileName = "trace_session-a.jsonl",
                lastModifiedAt = 10L,
            ),
        )

        val useCase = ListTraceSessionsUseCase(FakeTraceReplayService(sessions = sessions))

        assertEquals(sessions, useCase())
    }

    @Test
    fun `load trace replay report returns null when session file is missing`() {
        val useCase = LoadTraceReplayReportUseCase(
            traceReplayService = FakeTraceReplayService(),
            buildTraceReplayReportUseCase = BuildTraceReplayReportUseCase(),
        )

        assertNull(useCase("missing-session"))
    }

    @Test
    fun `load latest trace replay report uses newest stored session`() {
        val newestSession = TraceSessionDescriptor(
            sessionId = "session-newest",
            fileName = "trace_session-newest.jsonl",
            lastModifiedAt = 30L,
        )
        val olderSession = TraceSessionDescriptor(
            sessionId = "session-older",
            fileName = "trace_session-older.jsonl",
            lastModifiedAt = 10L,
        )
        val sessionLines = mapOf(
            newestSession.sessionId to listOf(
                """
                {"type":"session_start","sessionId":"session-newest","startedAt":1000,"pipelineMode":"semantic_only","targetHardwareProfile":"snapdragon_8_gen_3_plus"}
                """.trimIndent(),
                """
                {"type":"frame","sessionId":"session-newest","sequenceNumber":1,"frameTimestamp":1100,"frameWidth":640,"frameHeight":360,"droppedFramesSinceLast":0,"processFrameMs":20,"inferenceMs":12,"analyzeSceneMs":4,"decideEventsMs":3,"totalPipelineMs":29,"obstacleCount":1,"eventCount":1,"isBlocked":false,"isNarrowing":false,"isRoadDangerous":false,"messageKeys":["event_obstacle_center"]}
                """.trimIndent(),
            )
        )
        val replayService = FakeTraceReplayService(
            sessions = listOf(newestSession, olderSession),
            linesBySessionId = sessionLines,
        )

        val latestUseCase = LoadLatestTraceReplayReportUseCase(
            listTraceSessionsUseCase = ListTraceSessionsUseCase(replayService),
            loadTraceReplayReportUseCase = LoadTraceReplayReportUseCase(
                traceReplayService = replayService,
                buildTraceReplayReportUseCase = BuildTraceReplayReportUseCase(),
            ),
        )

        val report = latestUseCase()

        requireNotNull(report)
        assertEquals("session-newest", report.sessionId)
        assertEquals(1, report.totalFrames)
        assertTrue(report.uniqueMessageKeys.contains("event_obstacle_center"))
    }

    @Test
    fun `evaluate trace replay budget warns when latency and dropped frames exceed budget`() {
        val report = BuildTraceReplayReportUseCase()(
            listOf(
                """
                {"type":"session_start","sessionId":"session-budget","startedAt":1000,"pipelineMode":"combined","targetHardwareProfile":"snapdragon_8_gen_3_plus"}
                """.trimIndent(),
                """
                {"type":"frame","sessionId":"session-budget","sequenceNumber":1,"frameTimestamp":1100,"frameWidth":640,"frameHeight":360,"droppedFramesSinceLast":2,"processFrameMs":30,"inferenceMs":20,"analyzeSceneMs":10,"decideEventsMs":8,"totalPipelineMs":95,"obstacleCount":2,"eventCount":1,"isBlocked":true,"isNarrowing":false,"isRoadDangerous":true,"messageKeys":["event_blocked"]}
                """.trimIndent(),
            )
        )

        val evaluation = EvaluateTraceReplayBudgetUseCase()(report)

        assertTrue(evaluation.warnings.any { it.contains("p95 total pipeline") })
        assertTrue(evaluation.warnings.any { it.contains("dropped frame rate") })
    }
}

